1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PRICE = 60;
16	
17	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
18	
19	const sumItemPremiums = (items: any[]): number =>
20	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	
22	const groupByType = (items: any[]): Record<string, any[]> =>
23	  items.reduce((groups, item) => {
24	    (groups[item.type] ||= []).push(item);
25	    return groups;
26	  }, {} as Record<string, any[]>);
27	
28	const isCompleteBlock = (type: string, group: any[]): boolean =>
29	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
30	
31	const groupPremium = (type: string, group: any[]): number =>
32	  isCompleteBlock(type, group) ? BLOCK_PRICE : sumItemPremiums(group);
33	
34	const calculateBasePremium = (items: any[]): number =>
35	  Object.entries(groupByType(items)).reduce(
36	    (total, [type, group]) => total + groupPremium(type, group),
37	    0
38	  );
39	
40	const addPercent = (amount: number, percent: number): number =>
41	  amount + (amount * percent) / 100;
42	
43	const quotePremium = (items: any[]): number => {
44	  const base = calculateBasePremium(items);
45	  const withSurcharge = addPercent(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
46	  return Math.ceil(withSurcharge + PROCESSING_FEE);
47	};
48	
49	export const runScenario = (scenario: any): unknown => {
50	  const items = scenario.steps[0].items;
51	  return { results: [{ premium: quotePremium(items) }] };
52	};
