const addPercent = (amount: number, percent: number): number =>
  amount + (amount * percent) / 100;

const itemSurcharge = (item: any): number =>
  item.cursed ? itemBasePremium(item) * 0.5 : 0;

const calculateItemSurcharges = (items: any[]): number =>
  items.reduce((sum, item) => sum + itemSurcharge(item), 0);

const quotePremium = (items: any[]): number => {
  const policyBase = calculateBasePremium(items);
  const surcharges = calculateItemSurcharges(items);
  const withFirstInsurance = addPercent(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
  return Math.ceil(withFirstInsurance + surcharges + PROCESSING_FEE);
};
